16	/// A tracing subscriber layer that forwards formatted log records to a channel.
17	struct ChannelLayer {
18	    tx: mpsc::SyncSender<String>,
19	}
20	
21	impl<S> tracing_subscriber::Layer<S> for ChannelLayer
22	where
23	    S: tracing::Subscriber,
24	{
25	    fn on_event(
26	        &self,
27	        event: &tracing::Event<'_>,
28	        _ctx: tracing_subscriber::layer::Context<'_, S>,
29	    ) {
30	        let mut visitor = MessageVisitor(String::new());
31	        event.record(&mut visitor);
32	        let line = format!("[{}] {}", event.metadata().level(), visitor.0);
33	        // Non-blocking send — drop if buffer full to avoid blocking the UI thread.
34	        let _ = self.tx.try_send(line);
35	    }
36	}
37	
38	struct MessageVisitor(String);
39	
40	impl tracing::field::Visit for MessageVisitor {
41	    fn record_str(&mut self, field: &tracing::field::Field, value: &str) {
42	        if field.name() == "message" {
43	            self.0 = value.to_string();
44	        }
45	    }
46	    fn record_debug(&mut self, field: &tracing::field::Field, value: &dyn std::fmt::Debug) {
47	        if field.name() == "message" {
48	            self.0 = format!("{value:?}");
49	        }
50	    }
51	}
