53	// ── Mic level thread ─────────────────────────────────────────────────────────
54	
55	/// Shared mic level state: f32 RMS stored as bits in an AtomicU32.
56	struct MicLevelState {
57	    level: Arc<AtomicU32>,
58	    no_device: bool,
59	    _handle: Option<std::thread::JoinHandle<()>>,
60	}
61	
62	impl MicLevelState {
63	    fn current_level(&self) -> f32 {
64	        f32::from_bits(self.level.load(Ordering::Relaxed))
65	    }
66	}
67	
68	fn spawn_mic_level_thread() -> MicLevelState {
69	    let level = Arc::new(AtomicU32::new(0u32));
70	    let level_clone = Arc::clone(&level);
71	
72	    // no_device is signalled back from the thread via a one-shot channel.
73	    let (tx, rx) = std::sync::mpsc::sync_channel::<bool>(1);
74	
75	    // Build and play the stream inside the thread so the !Send stream never
76	    // crosses a thread boundary.
77	    let handle = std::thread::spawn(move || {
78	        use cpal::traits::{DeviceTrait, HostTrait, StreamTrait};
79	
80	        let host = cpal::default_host();
81	        let device = match host.default_input_device() {
82	            Some(d) => d,
83	            None => {
84	                tracing::warn!("Mic level: no default input device found");
85	                let _ = tx.send(true);
86	                return;
87	            }
88	        };
89	
90	        let config = match device.default_input_config() {
91	            Ok(c) => c,
92	            Err(e) => {
93	                tracing::error!(reason = %e, "Mic level: failed to get default input config");
94	                let _ = tx.send(true);
95	                return;
96	            }
97	        };
98	
99	        tracing::info!(
100	            device = device.name().unwrap_or_default(),
101	            sample_rate = config.sample_rate().0,
102	            channels = config.channels(),
103	            "Mic level thread: using device"
104	        );
105	
106	        let err_level = Arc::clone(&level_clone);
107	        let stream_result = device.build_input_stream(
108	            &config.into(),
109	            move |data: &[f32], _| {
110	                if data.is_empty() {
111	                    return;
112	                }
113	                let rms = (data.iter().map(|s| s * s).sum::<f32>() / data.len() as f32).sqrt();
114	                level_clone.store(rms.to_bits(), Ordering::Relaxed);
115	            },
116	            move |e| {
117	                tracing::error!(reason = %e, "Mic level: stream error");
118	                err_level.store(0u32, Ordering::Relaxed);
119	            },
120	            None,
121	        );
122	
123	        let stream = match stream_result {
124	            Ok(s) => s,
125	            Err(e) => {
126	                tracing::error!(reason = %e, "Mic level: failed to build input stream");
127	                let _ = tx.send(true);
128	                return;
129	            }
130	        };
131	
132	        if let Err(e) = stream.play() {
133	            tracing::error!(reason = %e, "Mic level: stream play failed");
134	            let _ = tx.send(true);
135	            return;
136	        }
137	
138	        let _ = tx.send(false);
139	        // Park the thread to keep the stream alive until the process exits.
140	        std::thread::park();
141	    });
142	
143	    let no_device = rx.recv().unwrap_or(true);
144	
145	    MicLevelState {
146	        level,
147	        no_device,
148	        _handle: Some(handle),
149	    }
150	}
