172	impl VibeAttackConfigApp {
173	    fn new(log_rx: mpsc::Receiver<String>) -> Self {
174	        use cpal::traits::{DeviceTrait, HostTrait};
175	
176	        let config_example_contents =
177	            include_str!(concat!(env!("CARGO_MANIFEST_DIR"), "/config.example.yaml"));
178	        let hd2_profile_contents =
179	            include_str!(concat!(env!("CARGO_MANIFEST_DIR"), "/profiles/hd2/pack.yaml"));
180	
181	        let first_run = probe::run();
182	        let setup_complete = first_run.is_setup_complete();
183	
184	        let mut config = ConfigApp::new();
185	        let mic;
186	
187	        // Enumerate input device names once at startup; degrade gracefully on failure.
188	        let device_names: Vec<String> = cpal::default_host()
189	            .input_devices()
190	            .map(|iter| iter.filter_map(|d| d.name().ok()).collect())
191	            .unwrap_or_default();
192	
193	        let mut cached_config = None;
194	
195	        if setup_complete {
196	            config.profiles = load_profiles();
197	            mic = spawn_mic_level_thread();
198	
199	            match load_config_into_app(&mut config, None) {
200	                Ok(cfg) => cached_config = Some(cfg),
201	                Err(e) => config.set_status(format!("Could not load config.yaml: {e}")),
202	            }
203	        } else {
204	            // Defer mic/profile load until after wizard completes
205	            mic = MicLevelState {
206	                level: Arc::new(AtomicU32::new(0)),
207	                no_device: false,
208	                _handle: None,
209	            };
210	        }
211	
212	        Self {
213	            first_run,
214	            config,
215	            ptt: PttCaptureState::new(),
216	            dl: ModelDownloadState::new(),
217	            uinput: UinputSetupState::new(),
218	            config_example_contents,
219	            hd2_profile_contents,
220	            mic,
221	            log_rx,
222	            setup_just_completed: false,
223	            tray: TrayHandle::spawn(),
224	            cached_config,
225	            device_names,
226	        }
227	    }
228	}
