230	impl eframe::App for VibeAttackConfigApp {
231	    fn ui(&mut self, ui: &mut egui::Ui, _frame: &mut eframe::Frame) {
232	        let ctx = ui.ctx().clone();
233	
234	        // Honour "Open Config" requests from the tray.
235	        if self.tray.as_ref().is_some_and(|t| t.take_open_request()) {
236	            ctx.send_viewport_cmd(egui::ViewportCommand::Focus);
237	        }
238	
239	        // Repaint at ~10Hz for mic level updates when in main config view.
240	        if self.first_run.is_setup_complete() {
241	            ctx.request_repaint_after(std::time::Duration::from_millis(100));
242	        }
243	
244	        // Repaint faster while PTT capture thread is listening.
245	        if self.ptt.listening {
246	            ctx.request_repaint_after(std::time::Duration::from_millis(50));
247	        }
248	
249	        // Repaint while model download is in progress.
250	        if self.dl.is_running() {
251	            ctx.request_repaint_after(std::time::Duration::from_millis(250));
252	        }
253	
254	        // Repaint while uinput setup actions are running.
255	        use vibe_attack::ui::wizard::SetupActionStatus;
256	        if matches!(self.uinput.modprobe, SetupActionStatus::Running)
257	            || matches!(self.uinput.usermod, SetupActionStatus::Running)
258	        {
259	            ctx.request_repaint_after(std::time::Duration::from_millis(200));
260	        }
261	
262	        // Drain log channel.
263	        while let Ok(line) = self.log_rx.try_recv() {
264	            self.config.add_log_line(line);
265	        }
266	
267	        // Update mic level from atomic.
268	        self.config.mic_level = self.mic.current_level();
269	        self.config.mic_no_device = self.mic.no_device;
270	
271	        // Refresh daemon-running status each frame (cheap socket stat).
272	        self.config.daemon_running = vibe_attack::control::client::is_daemon_running();
273	
274	        // Detect wizard completion and load profiles + start mic thread.
275	        if self.setup_just_completed {
276	            self.setup_just_completed = false;
277	            self.config.profiles = load_profiles();
278	            self.mic = spawn_mic_level_thread();
279	
280	            match load_config_into_app(&mut self.config, None) {
281	                Ok(cfg) => self.cached_config = Some(cfg),
282	                Err(e) => self.config.set_status(format!("Could not load config.yaml: {e}")),
283	            }
284	        }
285	
286	        ui.heading("Vibe Attack");
287	        ui.separator();
288	
289	        let was_incomplete = !self.first_run.is_setup_complete();
290	
291	        if !self.first_run.is_setup_complete() {
292	            show_wizard(
293	                ui,
294	                &mut self.first_run,
295	                &mut self.ptt,
296	                &mut self.dl,
297	                &mut self.uinput,
298	                self.config_example_contents,
299	                self.hd2_profile_contents,
300	            );
301	            // Detect transition to complete
302	            if was_incomplete && self.first_run.is_setup_complete() {
303	                self.setup_just_completed = true;
304	            }
305	        } else {
306	            show_main_config(ui, self);
307	        }
308	    }
309	}
