311	fn show_main_config(ui: &mut egui::Ui, app: &mut VibeAttackConfigApp) {
312	    // Daemon status row
313	    ui.horizontal(|ui| {
314	        if app.config.daemon_running {
315	            ui.colored_label(egui::Color32::GREEN, "● Daemon: running");
316	        } else {
317	            ui.colored_label(
318	                egui::Color32::from_rgb(255, 165, 0),
319	                "● Daemon: not running (changes will save to disk only)",
320	            );
321	        }
322	    });
323	
324	    ui.add_space(4.0);
325	
326	    // Mic level row
327	    ui.horizontal(|ui| {
328	        ui.label("Mic:");
329	        if app.config.mic_no_device {
330	            ui.label("no device");
331	        } else {
332	            ui.add(
333	                egui::ProgressBar::new(app.config.mic_level.clamp(0.0, 1.0))
334	                    .desired_width(200.0)
335	                    .show_percentage(),
336	            );
337	        }
338	    });
339	
340	    ui.add_space(4.0);
341	
342	    // Activation mode
343	    ui.horizontal(|ui| {
344	        ui.label("Mode:");
345	        ui.radio_value(&mut app.config.mode, ActivationMode::Ptt, "Push-to-talk");
346	        ui.radio_value(&mut app.config.mode, ActivationMode::Wake, "Wake word");
347	    });
348	
349	    // Confidence threshold slider
350	    ui.add(
351	        egui::Slider::new(&mut app.config.threshold_pct, 0u8..=100u8)
352	            .text("Confidence threshold (%)"),
353	    );
354	
355	    // Input device combo box
356	    let current_device_label = app
357	        .config
358	        .input_device
359	        .as_deref()
360	        .unwrap_or("<system default>")
361	        .to_string();
362	    egui::ComboBox::from_label("Input device")
363	        .selected_text(current_device_label)
364	        .show_ui(ui, |ui| {
365	            // Leading option: system default (maps to None)
366	            let is_default = app.config.input_device.is_none();
367	            if ui.selectable_label(is_default, "<system default>").clicked() {
368	                app.config.input_device = None;
369	            }
370	            for name in &app.device_names.clone() {
371	                let is_selected = app.config.input_device.as_deref() == Some(name.as_str());
372	                if ui.selectable_label(is_selected, name.as_str()).clicked() {
373	                    app.config.input_device = Some(name.clone());
374	                }
375	            }
376	        });
377	
378	    // PTT binding (read-only display — live capture deferred to post-S01)
379	    ui.horizontal(|ui| {
380	        ui.label(format!("PTT key: {}", app.config.ptt_binding));
381	    });
382	
383	    // Save button
384	    if ui.button("Save").clicked() {
385	        handle_save(app);
386	    }
387	
388	    // Status message
389	    if let Some(msg) = &app.config.status_message.clone() {
390	        ui.label(msg);
391	    }
392	
393	    ui.add_space(8.0);
394	
395	    // Profiles list
396	    ui.label(format!("Profiles ({})", app.config.profile_count()));
397	    if app.config.profiles.is_empty() {
398	        ui.weak("No profiles found in ~/.config/vibe-attack/profiles/");
399	    } else {
400	        for name in &app.config.profiles.clone() {
401	            let is_active = app.config.active_profile.as_deref() == Some(name.as_str());
402	            let _ = ui.selectable_label(is_active, name.as_str());
403	        }
404	    }
405	
406	    ui.separator();
407	    ui.label("Log:");
408	    egui::ScrollArea::vertical()
409	        .auto_shrink([false, false])
410	        .stick_to_bottom(true)
411	        .show(ui, |ui| {
412	            for line in &app.config.log_lines.clone() {
413	                ui.monospace(line.as_str());
414	            }
415	        });
416	}
