418	fn handle_save(app: &mut VibeAttackConfigApp) {
419	    use vibe_attack::control::client::send_command;
420	    use vibe_attack::control::protocol::ControlRequest;
421	
422	    let Some(cached) = app.cached_config.as_ref() else {
423	        app.config.set_status("No config loaded — cannot save.");
424	        return;
425	    };
426	
427	    match save_app_to_config(&app.config, cached, None) {
428	        Err(e) => {
429	            app.config.set_status(format!("Save failed: {e}"));
430	            return;
431	        }
432	        Ok(updated) => {
433	            app.cached_config = Some(updated);
434	        }
435	    }
436	
437	    if !app.config.daemon_running {
438	        app.config
439	            .set_status("Saved to disk — daemon not running, runtime changes skipped.");
440	        return;
441	    }
442	
443	    // Dispatch four control commands; collect any failures.
444	    let commands = [
445	        ControlRequest::SetMode { mode: app.config.mode.clone() },
446	        ControlRequest::SetThreshold {
447	            threshold: app.config.threshold_pct as f32 / 100.0,
448	        },
449	        ControlRequest::SetInputDevice {
450	            device: app.config.input_device.clone(),
451	        },
452	        ControlRequest::SetPttBinding {
453	            key: app.config.ptt_binding.clone(),
454	        },
455	    ];
456	
457	    let mut errors: Vec<String> = Vec::new();
458	    for cmd in commands {
459	        let label = format!("{cmd:?}");
460	        if let Err(e) = send_command(cmd) {
461	            errors.push(format!("Failed to send {label}: {e}"));
462	        }
463	    }
464	
465	    if errors.is_empty() {
466	        app.config.set_status("Saved and applied.");
467	    } else {
468	        app.config.set_status(errors.join("; "));
469	    }
470	}
