472	fn main() -> eframe::Result<()> {
473	    use tracing_subscriber::prelude::*;
474	
475	    // Log channel: bounded to 500 entries; oldest are dropped under pressure.
476	    let (log_tx, log_rx) = mpsc::sync_channel(500);
477	
478	    tracing_subscriber::registry()
479	        .with(tracing_subscriber::fmt::layer())
480	        .with(ChannelLayer { tx: log_tx })
481	        .init();
482	
483	    let options = eframe::NativeOptions {
484	        viewport: egui::ViewportBuilder::default()
485	            .with_title("Vibe Attack Config")
486	            .with_inner_size([720.0, 520.0]),
487	        ..Default::default()
488	    };
489	
490	    eframe::run_native(
491	        "Vibe Attack Config",
492	        options,
493	        Box::new(|_cc| Ok(Box::new(VibeAttackConfigApp::new(log_rx)))),
494	    )
495	}
